// Repeat capital questions for multiple cycles to enlarge the dataset.
function makeCapitalsQuestions(cycles) {
  for (let c = 0; c < cycles; c += 1) {
    for (const [country, capital] of capitals) {
      const decoys = shuffle(capitals.filter((x) => x[0] !== country)).slice(0, 3).map((x) => x[1]);
      const options = shuffle([capital, ...decoys]);
      pushQuestion({
        category: 'Geografia',
        difficulty: 'facil',
        question: `Cual es la capital de ${country}?`,
        options,
        answerIndex: options.indexOf(capital),
        explanation: `La capital de ${country} es ${capital}.`,
      });
    }
  }
}

